// Extrai informações estruturadas do erro capturado pelo Error Trigger
// $json aqui contém o contexto do erro fornecido pelo n8n
const errorData = $json;

const workflowName = (errorData.workflow && errorData.workflow.name) ? errorData.workflow.name : 'desconhecido';
const lastNode = (errorData.execution && errorData.execution.lastNodeExecuted) ? errorData.execution.lastNodeExecuted : 'desconhecido';
const errorMessage = (errorData.execution && errorData.execution.error && errorData.execution.error.message)
  ? errorData.execution.error.message
  : 'erro desconhecido';
const executionId = (errorData.execution && errorData.execution.id) ? String(errorData.execution.id) : '';

// Tenta extrair ingestion_id do contexto de dados da execução com falha
let ingestionId = '';
if (errorData.execution && errorData.execution.data && errorData.execution.data.resultData) {
  const resultData = errorData.execution.data.resultData;
  if (resultData.runData) {
    const nodeNames = Object.keys(resultData.runData);
    for (let i = 0; i < nodeNames.length; i++) {
      const nodeRuns = resultData.runData[nodeNames[i]];
      if (Array.isArray(nodeRuns) && nodeRuns.length > 0) {
        const firstRun = nodeRuns[0];
        if (firstRun.data && firstRun.data.main && firstRun.data.main[0] && firstRun.data.main[0][0]) {
          const item = firstRun.data.main[0][0];
          if (item.json && item.json.ingestion_id) {
            ingestionId = item.json.ingestion_id;
            break;
          }
          if (item.json && item.json.personaOutput && item.json.personaOutput.ingestion_id) {
            ingestionId = item.json.personaOutput.ingestion_id;
            break;
          }
        }
      }
    }
  }
}

return [{ json: {
  ts: new Date().toISOString(),
  ingestion_id: ingestionId,
  workflow: workflowName,
  node: lastNode,
  event: 'error',
  persona_tag: 'PIPELINE',
  duration_ms: 0,
  detail: 'execution_id=' + executionId,
  error: errorMessage
} }];
